import React, { useState, ChangeEvent, FormEvent } from 'react';
import ExportInventoryButton from './ExportInventoryButton';
import './InventoryPage.css';

interface InventoryItem {
    id: number;
    name: string;
    category: string;
    stock: number;
    weight: number;
    threshold: number;
    description?: string;
}

const sampleInventory: InventoryItem[] = [
    { id: 1, name: 'Laptop', category: 'Hardware', stock: 3, weight: 0, threshold: 5, description: 'High-performance laptop' },
    { id: 2, name: 'Headphones', category: 'Audio', stock: 15, weight: 0, threshold: 5, description: 'Noise-canceling headphones' },
    { id: 3, name: 'Mouse', category: 'Accessories', stock: 1, weight: 0, threshold: 5, description: 'Wireless mouse' },
];

export default function InventoryPage() {
    const [inventory, setInventory] = useState<InventoryItem[]>(sampleInventory);
    const [newProduct, setNewProduct] = useState<Omit<InventoryItem, 'id' | 'threshold'>>({
        name: '',
        category: '',
        stock: 0,
        weight: 0,
        description: '',
    });

    const handleInputChange = (e: ChangeEvent<HTMLInputElement>) => {
        const { name, value } = e.target;
        setNewProduct(prev => ({
            ...prev,
            [name]: name === 'stock' || name === 'weight'
                ? Number(value)
                : value,
        }));
    };

    const handleCreateProduct = (e: FormEvent) => {
        e.preventDefault();
        const id = inventory.length > 0 ? Math.max(...inventory.map(item => item.id)) + 1 : 1;
        const product: InventoryItem = {
            id,
            ...newProduct,
            threshold: newProduct.stock,
        };
        setInventory(prev => [...prev, product]);
        setNewProduct({ name: '', category: '', stock: 0, weight: 0, description: '' });
    };

    const handleRemoveProduct = (productId: number) => {
        setInventory(prev => prev.filter(item => item.id !== productId));
    };

    return (
        <div className="inventory-page-container">
            <h2>Inventory Management</h2>

            {/* Yeni Ürün Oluşturma Formu */}
            <form className="create-product-form" onSubmit={handleCreateProduct}>
                <input
                    name="name"
                    type="text"
                    placeholder="Ürün Adı"
                    value={newProduct.name}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="category"
                    type="text"
                    placeholder="Ürün Tipi"
                    value={newProduct.category}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="stock"
                    type="number"
                    placeholder="Enter quantity (adet)"
                    value={newProduct.stock}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="weight"
                    type="number"
                    placeholder="Kaç litre veya kilo"
                    value={newProduct.weight}
                    onChange={handleInputChange}
                    required
                />
                <input
                    name="description"
                    type="text"
                    placeholder="Açıklama (isteğe bağlı)"
                    value={newProduct.description}
                    onChange={handleInputChange}
                />
                <button type="submit" className="create-product-btn">Oluştur</button>
            </form>

            {/* Envanter Listesi ve Kaldırma */}
            <div className="inventory-status-container">
                <h3>Inventory Status</h3>
                <ul>
                    {inventory.map(item => (
                        <li key={item.id}>
                            {item.name}: {item.stock} adet{item.weight ? `, ${item.weight}` : ''}
                            <button
                                className="remove-btn"
                                onClick={() => handleRemoveProduct(item.id)}
                            >
                                Kaldır
                            </button>
                        </li>
                    ))}
                </ul>
            </div>

            {/* CSV / PDF Export */}
            <div className="export-buttons-container">
                <ExportInventoryButton items={inventory} />
            </div>
        </div>
    );
}
